const cfg = $('Config').first().json;
const runDate = cfg.runDate;
const TZ = 'America/Los_Angeles';
const allowPast = cfg.allowPast === true || cfg.allowPast === 'true';
const today = DateTime.now().setZone(TZ).toFormat('yyyy-LL-dd');
if (!allowPast && runDate <= today) throw new Error('Freeze guard: runDate ' + runDate + ' is today or in the past.');

const orResp = $('OR get_routes').first().json;
if (!orResp || orResp.success === false) throw new Error('OptimoRoute error: ' + JSON.stringify(orResp));

// visits: flatten 3 cursor-chained pages, dedup by id
const byId = {};
for (const nm of ['Visits p1', 'Visits p2', 'Visits p3']) {
  const j = $(nm).first().json;
  if (j.errors) throw new Error('Jobber ' + nm + ' error: ' + JSON.stringify(j.errors));
  const v = j.data && j.data.visits;
  if (v && v.nodes) for (const n of v.nodes) byId[n.id] = n;
}
const visits = Object.values(byId);

const usersJson = $('Jobber users').first().json;
if (usersJson.errors) throw new Error('Jobber users error: ' + JSON.stringify(usersJson.errors));
const nameToUser = {};
for (const u of usersJson.data.users.nodes) if (u.name && u.name.full) nameToUser[u.name.full.trim().toLowerCase()] = u.id;

const planByOrder = {}; const stopsByDriver = {};
for (const route of orResp.routes || []) {
  const driver = route.driverName || '(unassigned)';
  for (const s of route.stops || []) { stopsByDriver[driver] = (stopsByDriver[driver] || 0) + 1; planByOrder[String(s.orderNo)] = { driver, scheduledAtDt: s.scheduledAtDt }; }
}
const toPac = (iso) => DateTime.fromISO(iso, { zone: 'utc' }).setZone(TZ).toFormat('HH:mm');
const writeBack = [], timeFix = [], timedNotPlanned = [], unmatchedDriver = []; const seen = new Set();
for (const vis of visits) {
  const jn = vis.job && vis.job.jobNumber; if (jn == null) continue; seen.add(String(jn));
  const startP = toPac(vis.startAt); const anytime = startP === '00:00';
  const plan = planByOrder[String(jn)];
  if (plan) {
    const jobberUserId = nameToUser[plan.driver.trim().toLowerCase()] || null;
    if (!jobberUserId) unmatchedDriver.push({ job: String(jn), driver: plan.driver });
    const planTime = plan.scheduledAtDt ? plan.scheduledAtDt.slice(11, 16) : null;
    writeBack.push({ visitId: vis.id, job: String(jn), driver: plan.driver, jobberUserId, scheduledAtDt: plan.scheduledAtDt, planTime,
      curTime: anytime ? 'anytime' : startP, timeChange: (anytime ? 'anytime' : startP) !== planTime });
  } else if (anytime) { timeFix.push({ visitId: vis.id, job: String(jn) }); }
  else { timedNotPlanned.push({ visitId: vis.id, job: String(jn), time: startP }); }
}
const orphanOrders = Object.keys(planByOrder).filter(o => !seen.has(o));
return [{ json: { runDate, counts: { orStops: Object.keys(planByOrder).length, jobberVisits: visits.length,
  writeBack: writeBack.length, timeFix: timeFix.length, timedNotPlanned: timedNotPlanned.length,
  orphanOrders: orphanOrders.length, unmatchedDriver: unmatchedDriver.length },
  stopsByDriver, writeBack, timeFix, timedNotPlanned, unmatchedDriver, orphanOrders } }];

const plan = $('Plan').first().json;
let setTime = 0, assignable = 0;
for (const w of plan.writeBack) { if (w.timeChange) setTime++; if (w.jobberUserId) assignable++; }
return [{ json: { apply: { mode: 'DRY-RUN', setTime, assignable, timeFixed: plan.timeFix.length, errors: [] }, counts: plan.counts, runDate: plan.runDate } }];

const a = $('Apply').first().json; const c = a.counts;
const L = [];
L.push('Route sync — ' + a.runDate + ' — ' + a.apply.mode);
L.push('');
L.push('OptimoRoute stops: ' + c.orStops + '  |  Jobber visits: ' + c.jobberVisits);
L.push('Write-back (in plan): ' + c.writeBack + '  -> set time on ' + a.apply.setTime + ', assign ' + a.apply.assignable);
L.push('Time-fix (anytime -> 07:00-19:00): ' + c.timeFix);
L.push('Timed-but-not-routed (overflow?): ' + c.timedNotPlanned);
L.push('Unmatched driver: ' + c.unmatchedDriver + '  |  Orphan OR orders: ' + c.orphanOrders);
return [{ json: { subject: 'Route sync ' + a.runDate + ' — ' + a.apply.mode, text: L.join('\n'), counts: c,
  metrics: { mode: 'DRY-RUN', scheduled: a.apply.setTime, timeFixed: a.apply.timeFixed, errors: 0 } } }];

const cfg = $('Config').first().json;
const maxWrites = Number(cfg.maxWrites || 0);
const windowH = Number(cfg.customerWindowHours || 3);
const TZ = 'America/Los_Angeles';
const plan = $('Plan').first().json;
function sched(visitId, dt, hrs) {
  const s = DateTime.fromFormat(dt, 'yyyy-LL-dd HH:mm:ss', { zone: TZ });
  const e = s.plus({ hours: hrs });
  return 'mutation { visitEditSchedule(id: "' + visitId + '", input: { startAt: { date: "' + s.toFormat('yyyy-LL-dd') + '", time: "' + s.toFormat('HH:mm:ss') + '", timezone: "' + TZ + '" }, endAt: { date: "' + e.toFormat('yyyy-LL-dd') + '", time: "' + e.toFormat('HH:mm:ss') + '", timezone: "' + TZ + '" } }) { userErrors { message } } }';
}
const items = [];
for (const w of plan.writeBack) if (w.timeChange && w.scheduledAtDt) items.push({ kind: 'schedule', visitId: w.visitId, job: w.job, mutation: sched(w.visitId, w.scheduledAtDt, windowH) });
for (const t of plan.timeFix) items.push({ kind: 'timefix', visitId: t.visitId, job: t.job, mutation: sched(t.visitId, plan.runDate + ' 07:00:00', 12) });
const capped = items.slice(0, maxWrites);
if (!capped.length) return [{ json: { noop: true, wouldWrite: items.length } }];
return capped.map(i => ({ json: i }));

const emitted = $('Emit writes').all().map(i => i.json);
const results = $('Jobber mutate').all().map(i => i.json);
let ok = 0, failed = 0, noop = 0, okSched = 0, okFix = 0; const errors = []; const written = [];
for (let i = 0; i < emitted.length; i++) {
  if (emitted[i].noop) { noop++; continue; }
  const j = results[i] || {}; const ue = [];
  if (j.errors) ue.push(...j.errors.map(e => e.message));
  const d = j.data || {}; for (const k of Object.keys(d)) if (d[k] && d[k].userErrors) ue.push(...d[k].userErrors.map(e => e.message));
  if (ue.length) { failed++; errors.push(emitted[i].job + ': ' + ue.join('; ')); written.push(emitted[i].kind + ' job ' + emitted[i].job + ' FAILED'); }
  else { ok++; if (emitted[i].kind === 'timefix') okFix++; else okSched++; written.push(emitted[i].kind + ' job ' + emitted[i].job + ' (visit ' + emitted[i].visitId + ') OK'); }
}
const plan = $('Plan').first().json; const c = plan.counts;
const L = ['Route sync — ' + plan.runDate + ' — LIVE', ''];
L.push('Writes: ' + (emitted.length - noop) + ' attempted  |  ok ' + ok + '  |  failed ' + failed);
if (written.length) L.push('Written: ' + written.join(' ; '));
if (errors.length) L.push('errors: ' + errors.slice(0, 20).join(' | '));
L.push('', 'Plan: OR stops ' + c.orStops + ', visits ' + c.jobberVisits + ', write-back ' + c.writeBack + ', time-fix ' + c.timeFix + ', overflow ' + c.timedNotPlanned);
return [{ json: { subject: 'Route sync ' + plan.runDate + ' — LIVE (' + ok + ' ok, ' + failed + ' failed)', text: L.join('\n'),
  metrics: { mode: 'LIVE', scheduled: okSched, timeFixed: okFix, errors: failed } } }];
